#include <deque> // For managing free connections

class ConnectionPool {
private:
    std::vector<std::unique_ptr<Connection>> m_all_connections; // Stores all connections managed by the pool
    std::deque<Connection*> m_free_connections; // Pointers to available (free) connections
    std::mutex m_mutex;
    std::condition_variable m_cv;
    std::string m_host;
    int m_port;
    size_t m_max_pool_size;
    std::atomic<size_t> m_next_id; // For assigning unique IDs to new connections

public:
    ConnectionPool(const std::string& host, int port, size_t initial_size, size_t max_size);
    ~ConnectionPool();

    // Prevent copy/move semantics for ConnectionPool
    ConnectionPool(const ConnectionPool&) = delete;
    ConnectionPool& operator=(const ConnectionPool&) = delete;
    ConnectionPool(ConnectionPool&&) = delete;
    ConnectionPool& operator=(ConnectionPool&&) = delete;

    // Acquires a connection from the pool. Blocks if no connections are available and max_pool_size is reached.
    Connection* acquire();
    // Releases a connection back to the pool.
    void release(Connection* conn);
    // Closes all connections and clears the pool.
    void cleanup();

private:
    // Helper to create a new Connection object if pool size allows.
    std::unique_ptr<Connection> create_new_connection();
};

// ConnectionPool.cpp
#include "ConnectionPool.h"
#include <algorithm>
#include <chrono>

ConnectionPool::ConnectionPool(const std::string& host, int port, size_t initial_size, size_t max_size)
    : m_host(host), m_port(port), m_max_pool_size(max_size), m_next_id(0) {
    if (initial_size > max_size) {
        initial_size = max_size;
    }
    m_all_connections.reserve(max_size);

    for (size_t i = 0; i < initial_size; ++i) {
        std::unique_ptr<Connection> conn = create_new_connection();
        if (conn) {
            conn->connect(); // Try to connect initially
            // Only add to free_connections if it connected successfully
            if (conn->isConnected() && conn->isHealthy()) {
                m_free_connections.push_back(conn.get());
            } else {
                std::cerr << "Initial connection ID " << conn->getID() << " failed to connect. It will not be added to the free list initially.\n";
            }
            m_all_connections.push_back(std::move(conn)); // Always store unique_ptr, even if not connected
        }
    }
    std::cout << "ConnectionPool initialized with " << m_free_connections.size() << " healthy connections out of " << m_all_connections.size() << " total attempted.\n";
}

ConnectionPool::~ConnectionPool() {
    cleanup();
}

std::unique_ptr<Connection> ConnectionPool::create_new_connection() {
    if (m_all_connections.size() >= m_max_pool_size) {
        // std::cerr << "Pool size limit reached. Cannot create new connection.\n"; // This log can be noisy during wait
        return nullptr;
    }
    std::cout << "Creating new connection (ID: " << m_next_id << ").\n";
    return std::make_unique<Connection>(m_next_id++, m_host, m_port);
}

Connection* ConnectionPool::acquire() {
    std::unique_lock<std::mutex> lock(m_mutex);

    // Wait until a free connection is available or a new one can be created
    m_cv.wait(lock, [this]() {
        // Check for an existing free connection first
        for (Connection* conn : m_free_connections) {
            if (conn->isHealthy() && conn->isConnected()) {
                return true; // Found a good free connection
            }
        }
        // If no free healthy connections, check if we can create a new one
        return m_all_connections.size() < m_max_pool_size;
    });

    Connection* conn_ptr = nullptr;

    // Prioritize healthy, connected connections from the free list
    for (auto it = m_free_connections.begin(); it != m_free_connections.end(); ++it) {
        if ((*it)->isHealthy() && (*it)->isConnected()) {
            conn_ptr = *it;
            m_free_connections.erase(it);
            std::cout << "Acquired healthy connection ID " << conn_ptr->getID() << " from pool.\n";
            return conn_ptr;
        }
    }

    // If no healthy free connections, try to reconnect an unhealthy one
    // (Note: Connections are moved to m_all_connections when created, so we iterate that for potentially stale ones)
    for (auto& u_ptr_conn : m_all_connections) {
        if (!u_ptr_conn->isHealthy() || !u_ptr_conn->isConnected()) {
            std::cout << "Connection ID " << u_ptr_conn->getID() << " found unhealthy/disconnected. Attempting to reconnect.\n";
            if (u_ptr_conn->reconnect()) {
                conn_ptr = u_ptr_conn.get();
                std::cout << "Acquired reconnected connection ID " << conn_ptr->getID() << " from pool.\n";
                return conn_ptr;
            } else {
                std::cerr << "Failed to reconnect connection ID " << u_ptr_conn->getID() << ". It remains unhealthy.\n";
            }
        }
    }

    // If still no connection, try creating a new one (if allowed by m_max_pool_size)
    if (m_all_connections.size() < m_max_pool_size) {
        std::unique_ptr<Connection> new_conn_uptr = create_new_connection();
        if (new_conn_uptr) {
            conn_ptr = new_conn_uptr.get();
            if (conn_ptr->connect()) {
                m_all_connections.push_back(std::move(new_conn_uptr));
                std::cout << "Acquired newly created and connected connection ID " << conn_ptr->getID() << ".\n";
                return conn_ptr;
            } else {
                std::cerr << "Failed to connect new connection ID " << conn_ptr->getID() << ". Discarding.\n";
                // The new connection failed to connect, it won't be added to all_connections permanently if connect fails.
                // It was a unique_ptr, if it failed, it's discarded on function exit.
                conn_ptr = nullptr;
            }
        }
    }

    // If we reach here, no connection could be acquired
    std::cerr << "Failed to acquire any connection from the pool after all attempts.\n";
    return nullptr;
}

void ConnectionPool::release(Connection* conn) {
    if (!conn) return;

    std::unique_lock<std::mutex> lock(m_mutex);
    
    // Check if the connection is unhealthy or disconnected.
    // Proactively try to reconnect it before returning to the pool's free list.
    if (!conn->isHealthy() || !conn->isConnected()) {
        std::cerr << "Released connection ID " << conn->getID() << " is unhealthy/disconnected. Attempting to reconnect before returning to pool.\n";
        if (conn->reconnect()) {
            std::cout << "Connection ID " << conn->getID() << " reconnected successfully and returned to pool.\n";
            m_free_connections.push_back(conn); // Only add back if healthy and connected
        } else {
            std::cerr << "Connection ID " << conn->getID() << " failed to reconnect. It won't be returned to the free list.\n";
            // This connection is truly bad. We don't add it back to m_free_connections.
            // It remains in m_all_connections but will be ignored by acquire() unless it gets healthy later.
            // For a robust system, one might consider replacing such a connection.
        }
    } else {
        // Only add healthy and connected connections back to the free list
        m_free_connections.push_back(conn);
        std::cout << "Connection ID " << conn->getID() << " released to pool (healthy).\n";
    }

    // Notify waiting threads that a connection might be available
    lock.unlock(); // Release lock before notifying to avoid contention
    m_cv.notify_one(); 
}

void ConnectionPool::cleanup() {
    std::unique_lock<std::mutex> lock(m_mutex);
    m_free_connections.clear(); // Clear the free list (pointers), actual connections are in m_all_connections
    m_all_connections.clear(); // This will call destructors of unique_ptrs, closing sockets
    std::cout << "ConnectionPool cleaned up. All connections closed.\n";
}


